<template>
  <LTPages
      :title="'多选Select 提示'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">element-plus 的Select 选择器 组合 el-tooltip 自定义的多选Select 提示选择器。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div style="margin-bottom:15px;width: 300px;">
          <LTMultipleSelectTooltip :item="selectList"></LTMultipleSelectTooltip>
        </div>
        <!--2、代码示例-->
        <div class="zhb-title">代码示例</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTTooltip1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTActionsForm2" title="javaScript"></codeCopy>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--4、item配置参数-->
        <div class="zhb-title">item配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="itemTableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>




      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      selectList:{
        type: "multipleSelect",
        prop: "labelType",
        label: "标签",
        isSelectAll: true,
        isFilterable: true,
        isDisabled: false,
        list: [
          { label: "选项1", value: 1 },
          { label: "选项2", value: 2 },
          { label: "选项3", value: 3 },
          { label: "选项4", value: 4 },
          { label: "选项5", value: 5 }
        ],
        value: [1, 2]
      },
      mainCode: `<template>
  <LTMultipleSelectTooltip :item="selectList" @setMultipleSelectValue="getMultipleSelectValue"></LTMultipleSelectTooltip>
</template>
`,
      jsCode: `export default {
  data() {
    return {
      selectList:{
        type: "multipleSelect",
        prop: "labelType",
        label: "标签",
        isSelectAll: true,
        isFilterable: true,
        isDisabled: false,
        list: [
          { label: "选项1", value: 1 },
          { label: "选项2", value: 2 },
          { label: "选项3", value: 3 },
          { label: "选项4", value: 4 },
          { label: "选项5", value: 5 }
        ],
        value: [1, 2]
      }
    }
  }
}`,
      // 配置参数
      tableData: [
        {
          text1:'item',
          text2:'多选Select选择器数据',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'@setMultipleSelectValue',
          text2:'change数据返回',
          text3:'Funtion',
          text4:'---',
          text5:'---',
          text6:'---',
        }
      ],
      // item配置参数
      itemTableData: [
        {
          text1:'type',
          text2:'类型',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'prop',
          text2:'枚举值',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'必填',
        },
        {
          text1:'label',
          text2:'枚举类型',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'必填',
        },
        {
          text1:'isSelectAll',
          text2:'是否需要全选按钮',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'isFilterable',
          text2:'是否需要过滤',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'isDisabled',
          text2:'是否禁止选择',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'list',
          text2:'下拉框数据',
          text3:'Array',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'value',
          text2:'默认显示枚举值',
          text3:'Array',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
      ]


    }
  }
}
</script>

